     * Override the image size for this specific call.
     * e.g., "256x256", "512x512", "1024x1024"
     */
    size: z.string().optional(),
    /**
     * Override the artistic style for this specific call.
     */
    style: z.enum(['pixel', 'retro', '8bit']).optional(),
    /**
     * Override the pixel density for this specific call.
     */
    pixelDensity: z.number().optional(),
  }),
);

// Success response schema for https://api.pixelart.ai/v1/images/generate
const pixelArtImageResponseSchema = z.object({
  created: z.number(),
  data: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

// Error response schema
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().optional(),
    code: z.string().optional(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3' as const;
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      abortSignal,
      headers,
      files,
      mask,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // Warn about unsupported standard features
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size setting instead (e.g., "512x512").',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support seed-based generation.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image input',
        details:
          'PixelArt does not support image-to-image generation. Input files will be ignored.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details:
          'PixelArt does not support mask-based inpainting. The mask will be ignored.',
      });
    }

    // Parse per-call provider options (providerOptions.pixelart)
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Resolve effective settings: per-call options override model-level settings,
    // which override the standard `size` parameter.
    const effectiveSize =
      pixelArtOptions?.size ?? size ?? this.settings.size;
    const effectiveStyle =
      pixelArtOptions?.style ?? this.settings.style;
    const effectivePixelDensity =
      pixelArtOptions?.pixelDensity ?? this.settings.pixelDensity;

    const requestBody: Record<string, unknown> = {
      prompt,
      n,
      ...(effectiveSize != null && { size: effectiveSize }),
      ...(effectiveStyle != null && { style: effectiveStyle }),
      ...(effectivePixelDensity != null && {
        pixel_density: effectivePixelDensity,
      }),
    };

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: value.data.map(item => ({ b64Json: item.b64_json })),
          created: value.created,
        },
      },
    };
  }
}

